={{ (() => {
  const sysMsg = "You are an expert OCR system for shipping and trade documents (Bill of Lading, Commercial Invoice, Packing List). Extract ALL structured data visible on THIS PAGE and return ONLY valid JSON (no markdown, no code blocks) with exactly these fields. For BL documents: shipper=vendor_name, B/L No=bl_number, vessel=vessel_name, POL=port_of_loading, POD=port_of_discharge. For invoices: use invoice_number, invoice_date. Capture EVERY field visible anywhere on the page, including small print, stamps, tables, bank details boxes, and signature blocks. Always populate raw_text with ALL visible text on this page. Use null for fields not present on this page. Return: {document_type,vendor_name,vendor_address,consignee_name,consignee_address,invoice_number,invoice_date,bl_number,vessel_name,port_of_loading,port_of_discharge,total_amount,currency,po_number,sales_order_number,customer_ref,payment_term,delivery_term,fob_value,freight_amount,insurance_amount,bank_name,bank_account_number,bank_swift_code,bank_beneficiary,bank_address,signatory_name,signatory_title,line_items:[{description,hs_code,quantity,unit,unit_price,discount_amount,amount}],raw_text}";
  const userText = "Extract all structured data from this shipping document page. File: " + $json.fileName + " (page " + $json.page + " of " + $json.totalPages + ")";
  const userContent = [
    { type: "text", text: userText },
    { type: "image_url", image_url: { url: $json.imageUrl, detail: "high" } }
  ];
  return JSON.stringify({ messages: [{ role: "system", content: sysMsg }, { role: "user", content: userContent }], temperature: 0, max_tokens: 4096 });
})() }}

