const raw = $json.choices?.[0]?.message?.content || '{}';
let extracted;
try {
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```/g, '').trim();
  extracted = JSON.parse(cleaned);
} catch (e) {
  extracted = { raw_text: raw, parse_error: e.message };
}
const pageMeta = $('Merge Pages').item.json;
return { json: {
  documentId: pageMeta.documentId,
  runId: pageMeta.runId,
  fileName: pageMeta.fileName,
  startedAt: pageMeta.startedAt,
  page: pageMeta.page,
  totalPages: pageMeta.totalPages,
  extractedData: extracted,
  rawText: extracted.raw_text || raw
}};

const items = $input.all().map(i => i.json).sort((a, b) => (a.page || 0) - (b.page || 0));
const meta = items[0] || {};
const totalPages = meta.totalPages || items.length;

const pages = items.map(it => ({
  page: it.page,
  extracted_data: it.extractedData,
  raw_text: it.rawText
}));

// Merge structured fields across pages: first non-null wins, line_items concatenated
const scalarFields = ['document_type','vendor_name','vendor_address','consignee_name','consignee_address','invoice_number','invoice_date','bl_number','vessel_name','port_of_loading','port_of_discharge','total_amount','currency','po_number','sales_order_number','customer_ref','payment_term','delivery_term','fob_value','freight_amount','insurance_amount','bank_name','bank_account_number','bank_swift_code','bank_beneficiary','bank_address','signatory_name','signatory_title'];
const merged = {};
for (const f of scalarFields) {
  merged[f] = null;
  for (const it of items) {
    const v = it.extractedData?.[f];
    if (v !== null && v !== undefined && v !== '') { merged[f] = v; break; }
  }
}
merged.line_items = items.flatMap(it => Array.isArray(it.extractedData?.line_items) ? it.extractedData.line_items : []);
merged.page_count = totalPages;

const rawTextCombined = items.map(it => `--- Page ${it.page} of ${totalPages} ---\n${it.rawText || ''}`).join('\n\n');

return [{ json: {
  documentId: meta.documentId,
  runId: meta.runId,
  fileName: meta.fileName,
  startedAt: meta.startedAt,
  totalPages,
  extractedData: merged,
  rawText: rawTextCombined,
  pages,
  confidenceScore: 0.95,
  modelUsed: 'gpt-4o-mini',
  processingMs: Date.now() - new Date(meta.startedAt).getTime()
}}];
